package com.oneil.wellness.walkplanner.calendar;
import static org.junit.jupiter.api.Assertions.*;import com.oneil.wellness.walkplanner.calendar.model.*;import com.oneil.wellness.walkplanner.calendar.provider.google.GoogleProviderException;import com.oneil.wellness.walkplanner.calendar.service.CalendarSyncService;import java.time.OffsetDateTime;import java.util.*;import org.junit.jupiter.api.Test;
class CalendarProviderContractIT {
 @Test void oauthProviderFailurePreservesOtherNormalizedProviderEvents(){OffsetDateTime start=OffsetDateTime.parse("2026-07-20T09:00:00Z"),end=start.plusHours(1);CalendarEvent caldav=new CalendarEvent("caldav:one","Busy",start,end,true,CalendarSource.CALDAV,CalendarProviderType.CALDAV,"one","caldav-one",start.toInstant().toString(),"Z",false);CalendarEvent manual=new CalendarEvent("manual:one","Manual",start.plusHours(2),end.plusHours(2),true,CalendarSource.MANUAL);var service=new CalendarSyncService(new CalendarProviderRegistry(List.of(new SuccessfulProvider(caldav),new FailingGoogleProvider())));var result=service.synchronize(start,start.plusDays(1),List.of(manual));assertEquals(Set.of(CalendarSource.MANUAL,CalendarSource.CALDAV),result.events().stream().map(CalendarEvent::source).collect(java.util.stream.Collectors.toSet()));assertTrue(result.isPartial());assertEquals(CalendarProviderType.GOOGLE,result.errors().getFirst().providerType());}
 static class SuccessfulProvider implements CalendarProvider{private final CalendarEvent event;SuccessfulProvider(CalendarEvent e){event=e;}public CalendarProviderType getType(){return CalendarProviderType.CALDAV;}public String getDisplayName(){return "CalDAV";}public boolean isEnabled(){return true;}public CalendarConnectionStatus getConnectionStatus(){return CalendarConnectionStatus.CONNECTED;}public CalendarConnectionResult testConnection(){return new CalendarConnectionResult(CalendarConnectionStatus.CONNECTED,"OK");}public List<CalendarEvent> fetchEvents(OffsetDateTime s,OffsetDateTime e){return List.of(event);}public CalendarProviderCapabilities getCapabilities(){return CalendarProviderCapabilities.readOnly(true,true);}}
 static class FailingGoogleProvider extends SuccessfulProvider{FailingGoogleProvider(){super(null);}public CalendarProviderType getType(){return CalendarProviderType.GOOGLE;}public List<CalendarEvent> fetchEvents(OffsetDateTime s,OffsetDateTime e){throw new GoogleProviderException("AUTHORIZATION_REQUIRED","Google authorization is required.",true);}}
}
